"""
Manages the Checkers (Draughts) game state.
"""

from board import Board
from player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.player_black = Player("black")
        self.player_red = Player("red")
        self.current_player = self.player_black

    def start(self):
        while not self.board.check_win() and not self.board.check_draw():
            self.board.display()
            move = self.current_player.make_move(self.board)
            self.board.make_move(move[0], move[1])
            self.switch_turn()

    def switch_turn(self):
        if self.current_player == self.player_black:
            self.current_player = self.player_red
        else:
            self.current_player = self.player_black

if __name__ == "__main__":
    game = Game()
    game.start()
